mapper.sql:
-- 1. 清理旧数据（初始化=用系统模板覆盖） DELETE FROM fin_report_items WHERE groupid = #{groupId} AND template_id IN (SELECT id FROM fin_report_templates WHERE template_code = 'BALANCE_SHEET_STANDARD' AND groupid = #{groupId}); DELETE FROM fin_report_templates WHERE template_code = 'BALANCE_SHEET_STANDARD' AND groupid = #{groupId};
-- 2. 创建模板 INSERT INTO fin_report_templates (groupid, template_code, template_name, template_type, description, created_by) VALUES (#{groupId}, 'BALANCE_SHEET_STANDARD', '资产负债报告', 'BALANCE_SHEET', '新会计准则标准资产负债表模板', 'system'); SET @template_id = LAST_INSERT_ID();
-- 3. 插入报表项目 -- parent_code 规则： -- 合计项(如 ASSET_CURRENT_TOTAL)的 parent_code 指向上一级分组(如 ASSET)， -- 而非同级分组头(如 ASSET_CURRENT)，避免 CUSTOM 计算时循环引用导致金额翻倍。 -- line_number 规则：资产侧 1-19，负债侧 21-35，权益侧 36-43，各区域不重复。 INSERT INTO fin_report_items (groupid, template_id, item_code, item_name, parent_code, item_level, line_number, item_type, calculation_rule, formula_type, sort_order, is_leaf, is_show) VALUES -- ===== 资产部分 ===== -- 注意：ASSET（汇总行）必须排在 ASSET_CURRENT_TOTAL 和 ASSET_NON_CURRENT_TOTAL 之后， -- 因为后端按 INSERT 顺序处理同级项目，ASSET 的公式依赖这两个合计项的值。 -- 流动资产分组头（CUSTOM 计算，会通过映射规则或子项汇总） (#{groupId}, @template_id, 'ASSET_CURRENT', '流动资产', 'ASSET', 2, NULL, 'ASSET', 'CUSTOM:ASSET_CURRENT', 'CUSTOM', 20, 0, 1), -- 流动资产叶子项 (#{groupId}, @template_id, 'ASSET_CASH', '货币资金', 'ASSET_CURRENT', 3, 1, 'ASSET', '1001+1002+1012', 'FORMULA', 30, 1, 1), (#{groupId}, @template_id, 'ASSET_FINANCIAL', '交易性金融资产', 'ASSET_CURRENT', 3, 2, 'ASSET', '1101', 'DIRECT', 40, 1, 1), (#{groupId}, @template_id, 'ASSET_BILLS', '应收票据', 'ASSET_CURRENT', 3, 3, 'ASSET', '1121', 'DIRECT', 50, 1, 1), (#{groupId}, @template_id, 'ASSET_RECEIVABLE', '应收账款', 'ASSET_CURRENT', 3, 4, 'ASSET', '1122-1231', 'FORMULA', 60, 1, 1), (#{groupId}, @template_id, 'ASSET_PREPAY', '预付款项', 'ASSET_CURRENT', 3, 5, 'ASSET', '1123', 'DIRECT', 70, 1, 1), (#{groupId}, @template_id, 'ASSET_INVENTORY', '存货', 'ASSET_CURRENT', 3, 6, 'ASSET', '1401+1403+1405+1406+1408+1411-1471', 'FORMULA', 80, 1, 1), (#{groupId}, @template_id, 'ASSET_CURRENT_OTHER', '其他流动资产', 'ASSET_CURRENT', 3, 7, 'ASSET', 'CUSTOM:ASSET_CURRENT_OTHER', 'CUSTOM', 90, 1, 1), -- 流动资产合计：parent_code=ASSET（不是ASSET_CURRENT！），公式直接引用ASSET_CURRENT (#{groupId}, @template_id, 'ASSET_CURRENT_TOTAL', '流动资产合计', 'ASSET', 2, 10, 'ASSET', 'ASSET_CURRENT', 'FORMULA', 100, 1, 1),
-- 非流动资产分组头 (#{groupId}, @template_id, 'ASSET_NON_CURRENT', '非流动资产', 'ASSET', 2, NULL, 'ASSET', 'CUSTOM:ASSET_NON_CURRENT', 'CUSTOM', 110, 0, 1), -- 非流动资产叶子项 (#{groupId}, @template_id, 'ASSET_LONG_INVEST', '长期股权投资', 'ASSET_NON_CURRENT', 3, 11, 'ASSET', '1511', 'DIRECT', 120, 1, 1), (#{groupId}, @template_id, 'ASSET_FIXED', '固定资产', 'ASSET_NON_CURRENT', 3, 12, 'ASSET', '1601-1602-1603', 'FORMULA', 130, 1, 1), (#{groupId}, @template_id, 'ASSET_CONSTRUCTION', '在建工程', 'ASSET_NON_CURRENT', 3, 13, 'ASSET', '1604', 'DIRECT', 140, 1, 1), (#{groupId}, @template_id, 'ASSET_INTANGIBLE', '无形资产', 'ASSET_NON_CURRENT', 3, 14, 'ASSET', '1701-1702-1703', 'FORMULA', 150, 1, 1), (#{groupId}, @template_id, 'ASSET_DEFERRED', '长期待摊费用', 'ASSET_NON_CURRENT', 3, 15, 'ASSET', '1801', 'DIRECT', 160, 1, 1), (#{groupId}, @template_id, 'ASSET_NON_CURRENT_OTHER', '其他非流动资产', 'ASSET_NON_CURRENT', 3, 16, 'ASSET', 'CUSTOM:ASSET_NON_CURRENT_OTHER', 'CUSTOM', 170, 1, 1), -- 非流动资产合计：parent_code=ASSET，公式直接引用ASSET_NON_CURRENT (#{groupId}, @template_id, 'ASSET_NON_CURRENT_TOTAL', '非流动资产合计', 'ASSET', 2, 18, 'ASSET', 'ASSET_NON_CURRENT', 'FORMULA', 180, 1, 1),
-- ASSET 汇总行：必须排在两个合计项之后！ (#{groupId}, @template_id, 'ASSET', '资产', NULL, 2, 19, 'ASSET', 'ASSET_CURRENT_TOTAL+ASSET_NON_CURRENT_TOTAL', 'FORMULA', 10, 1, 1),
-- ===== 负债和所有者权益部分 ===== (#{groupId}, @template_id, 'LIABILITY_EQUITY', '负债和所有者权益', NULL, 1, NULL, 'LIABILITY', NULL, 'DIRECT', 200, 0, 1), -- LIABILITY 是负债汇总行，level=2, line=35 (#{groupId}, @template_id, 'LIABILITY', '负债', 'LIABILITY_EQUITY', 2, 35, 'LIABILITY', 'LIABILITY_CURRENT_TOTAL+LIABILITY_NON_CURRENT_TOTAL', 'FORMULA', 210, 1, 1), -- 流动负债分组头 (#{groupId}, @template_id, 'LIABILITY_CURRENT', '流动负债', 'LIABILITY', 3, NULL, 'LIABILITY', 'CUSTOM:LIABILITY_CURRENT', 'CUSTOM', 220, 0, 1), -- 流动负债叶子项 (#{groupId}, @template_id, 'LIABILITY_SHORT_LOAN', '短期借款', 'LIABILITY_CURRENT', 4, 21, 'LIABILITY', '2001', 'DIRECT', 230, 1, 1), (#{groupId}, @template_id, 'LIABILITY_BILLS', '应付票据', 'LIABILITY_CURRENT', 4, 22, 'LIABILITY', '2201', 'DIRECT', 240, 1, 1), (#{groupId}, @template_id, 'LIABILITY_PAYABLE', '应付账款', 'LIABILITY_CURRENT', 4, 23, 'LIABILITY', '2202', 'DIRECT', 250, 1, 1), (#{groupId}, @template_id, 'LIABILITY_ADVANCE', '预收款项', 'LIABILITY_CURRENT', 4, 24, 'LIABILITY', '2203', 'DIRECT', 260, 1, 1), (#{groupId}, @template_id, 'LIABILITY_SALARY', '应付职工薪酬', 'LIABILITY_CURRENT', 4, 25, 'LIABILITY', '2211', 'DIRECT', 270, 1, 1), (#{groupId}, @template_id, 'LIABILITY_TAX', '应交税费', 'LIABILITY_CURRENT', 4, 26, 'LIABILITY', '2221', 'DIRECT', 280, 1, 1), (#{groupId}, @template_id, 'LIABILITY_CURRENT_OTHER', '其他流动负债', 'LIABILITY_CURRENT', 4, 27, 'LIABILITY', 'CUSTOM:LIABILITY_CURRENT_OTHER', 'CUSTOM', 290, 1, 1), -- 流动负债合计：parent_code=LIABILITY（不是LIABILITY_CURRENT！） (#{groupId}, @template_id, 'LIABILITY_CURRENT_TOTAL', '流动负债合计', 'LIABILITY', 3, 29, 'LIABILITY', 'LIABILITY_CURRENT', 'FORMULA', 300, 1, 1),
-- 非流动负债分组头 (#{groupId}, @template_id, 'LIABILITY_NON_CURRENT', '非流动负债', 'LIABILITY', 3, NULL, 'LIABILITY', 'CUSTOM:LIABILITY_NON_CURRENT', 'CUSTOM', 310, 0, 1), -- 非流动负债叶子项 (#{groupId}, @template_id, 'LIABILITY_LONG_LOAN', '长期借款', 'LIABILITY_NON_CURRENT', 4, 30, 'LIABILITY', '2501', 'DIRECT', 320, 1, 1), (#{groupId}, @template_id, 'LIABILITY_BONDS', '应付债券', 'LIABILITY_NON_CURRENT', 4, 31, 'LIABILITY', '2502', 'DIRECT', 330, 1, 1), (#{groupId}, @template_id, 'LIABILITY_NON_CURRENT_OTHER', '其他非流动负债', 'LIABILITY_NON_CURRENT', 4, 32, 'LIABILITY', 'CUSTOM:LIABILITY_NON_CURRENT_OTHER', 'CUSTOM', 340, 1, 1), -- 非流动负债合计：parent_code=LIABILITY（不是LIABILITY_NON_CURRENT！） (#{groupId}, @template_id, 'LIABILITY_NON_CURRENT_TOTAL', '非流动负债合计', 'LIABILITY', 3, 34, 'LIABILITY', 'LIABILITY_NON_CURRENT', 'FORMULA', 350, 1, 1),
-- ===== 权益部分 ===== (#{groupId}, @template_id, 'EQUITY', '所有者权益', 'LIABILITY_EQUITY', 2, 36, 'EQUITY', NULL, 'DIRECT', 370, 0, 1), (#{groupId}, @template_id, 'EQUITY_CAPITAL', '实收资本', 'EQUITY', 3, 37, 'EQUITY', '3001', 'DIRECT', 380, 1, 1), (#{groupId}, @template_id, 'EQUITY_RESERVE', '资本公积', 'EQUITY', 3, 38, 'EQUITY', '3002', 'DIRECT', 390, 1, 1), (#{groupId}, @template_id, 'EQUITY_SURPLUS', '盈余公积', 'EQUITY', 3, 39, 'EQUITY', '3101', 'DIRECT', 400, 1, 1), (#{groupId}, @template_id, 'EQUITY_RETAINED', '未分配利润', 'EQUITY', 3, 40, 'EQUITY', '3104', 'DIRECT', 410, 1, 1), (#{groupId}, @template_id, 'EQUITY_OTHER', '其他所有者权益', 'EQUITY', 3, 41, 'EQUITY', 'CUSTOM:EQUITY_OTHER', 'CUSTOM', 420, 1, 1), (#{groupId}, @template_id, 'EQUITY_TOTAL', '权益合计', 'EQUITY', 3, 42, 'EQUITY', 'EQUITY_CAPITAL+EQUITY_RESERVE+EQUITY_SURPLUS+EQUITY_RETAINED+EQUITY_OTHER', 'FORMULA', 430, 1, 1),
-- 负债和权益总计：引用 LIABILITY + EQUITY_TOTAL (#{groupId}, @template_id, 'LIABILITY_EQUITY_TOTAL', '负债和权益总计', 'LIABILITY_EQUITY', 2, 43, 'LIABILITY', 'LIABILITY+EQUITY_TOTAL', 'FORMULA', 440, 1, 1);
